import {
  openai,
  type OpenAILanguageModelResponsesOptions,
} from '@ai-sdk/openai';
import {
  convertToModelMessages,
  createUIMessageStreamResponse,
  streamText,
  toUIMessageStream,
  type InferUITools,
  type UIDataTypes,
  type UIMessage,
} from 'ai';
const tools = {
  web_search: openai.tools.webSearch({
    searchContextSize: 'high',
    userLocation: {
      type: 'approximate',
      city: 'San Francisco',
      region: 'California',
      country: 'US',
    },
  }),
} as const;

export type ReasoningToolsMessage = UIMessage<
  never, // could define metadata here
  UIDataTypes, // could define data parts here
  InferUITools<typeof tools>
>;

// Allow streaming responses up to 30 seconds
export const maxDuration = 30;

export async function POST(req: Request) {
  const { messages } = await req.json();

  console.log(JSON.stringify(messages, null, 2));

  const result = streamText({
    model: openai('gpt-5'),
    messages: await convertToModelMessages(messages),
    tools,
    providerOptions: {
      openai: {
        reasoningSummary: 'detailed', // 'auto' for condensed or 'detailed' for comprehensive
      } satisfies OpenAILanguageModelResponsesOptions,
    },
  });

  return createUIMessageStreamResponse({
    stream: toUIMessageStream({ stream: result.stream }),
  });
}

export type OpenAIChatPrompt = Array<ChatCompletionMessage>;

export type ChatCompletionMessage =
  | ChatCompletionSystemMessage
  | ChatCompletionDeveloperMessage
  | ChatCompletionUserMessage
  | ChatCompletionAssistantMessage
  | ChatCompletionToolMessage;

export interface ChatCompletionSystemMessage {
  role: 'system';
  content: string;
}

export interface ChatCompletionDeveloperMessage {
  role: 'developer';
  content: string;
}

export interface ChatCompletionUserMessage {
  role: 'user';
  content: string | Array<ChatCompletionContentPart>;
}

export type ChatCompletionContentPart =
  | ChatCompletionContentPartText
  | ChatCompletionContentPartImage
  | ChatCompletionContentPartInputAudio
  | ChatCompletionContentPartFile;

export interface ChatCompletionContentPartText {
  type: 'text';
  text: string;
}

export interface ChatCompletionContentPartImage {
  type: 'image_url';
  image_url: { url: string };
}

export interface ChatCompletionContentPartInputAudio {
  type: 'input_audio';
  input_audio: { data: string; format: 'wav' | 'mp3' };
}

export interface ChatCompletionContentPartFile {
  type: 'file';
  file: { filename: string; file_data: string } | { file_id: string };
}

export interface ChatCompletionAssistantMessage {
  role: 'assistant';
  content?: string | null;
  tool_calls?: Array<ChatCompletionMessageToolCall>;
}

export interface ChatCompletionMessageToolCall {
  type: 'function';
  id: string;
  function: {
    arguments: string;
    name: string;
  };
}

export interface ChatCompletionToolMessage {
  role: 'tool';
  content: string;
  tool_call_id: string;
}

import { ComponentPropsService } from "@sitecore-jss/sitecore-jss-nextjs";
import { SitecorePageProps } from "lib/page-props";
import { GetServerSidePropsContext, GetStaticPropsContext } from "next";
import { componentModule } from "temp/componentFactory";
import { Plugin, isServerSidePropsContext } from "..";

class ComponentPropsPlugin implements Plugin {
  private componentPropsService: ComponentPropsService;

  order = 2;

  constructor() {
    this.componentPropsService = new ComponentPropsService();
  }

  async exec(
    props: SitecorePageProps,
    context: GetServerSidePropsContext | GetStaticPropsContext,
  ) {
    if (!props.layoutData.sitecore.route) return props;

    // Retrieve component props using side-effects defined on components level
    if (isServerSidePropsContext(context)) {
      props.componentProps =
        await this.componentPropsService.fetchServerSideComponentProps({
          layoutData: props.layoutData,
          context,
          componentModule,
        });
    } else {
      props.componentProps =
        await this.componentPropsService.fetchStaticComponentProps({
          layoutData: props.layoutData,
          context,
          componentModule,
        });
    }

    return props;
  }
}

export const componentPropsPlugin = new ComponentPropsPlugin();

export interface ProxyServer {
  readonly port: number
  fetchWith(
    input: string | URL,
    init?: RequestInit,
    testData?: string
  ): Promise<Response>
  close(): void
}

interface ProxyRequestBase {
  testData: string
  api: string
}

interface ProxyResponseBase {
  api: string
}

export interface ProxyUnhandledResponse extends ProxyResponseBase {
  api: 'unhandled'
}

export interface ProxyAbortResponse extends ProxyResponseBase {
  api: 'abort'
}

export interface ProxyContinueResponse extends ProxyResponseBase {
  api: 'continue'
}

export interface ProxyFetchRequest extends ProxyRequestBase {
  api: 'fetch'
  request: {
    url: string
    headers: Array<[string, string]>
    body: string | null
  } & Omit<RequestInit, 'headers' | 'body'>
}

export interface ProxyFetchResponse extends ProxyResponseBase {
  api: 'fetch'
  response: {
    status: number
    headers: Array<[string, string]>
    body: string | null
  }
}

export type ProxyRequest = ProxyFetchRequest

export type ProxyResponse =
  | ProxyUnhandledResponse
  | ProxyAbortResponse
  | ProxyContinueResponse
  | ProxyFetchResponse

export const ABORT: ProxyResponse = { api: 'abort' }
export const CONTINUE: ProxyResponse = { api: 'continue' }
export const UNHANDLED: ProxyResponse = { api: 'unhandled' }
